const coupons = [];

function redeemCoupon(couponCode) {
  const coupon = coupons.find(c => c.code === couponCode);

  if (!coupon) {
    return "Invalid coupon code.";
  }

  if (coupon.isExpired()) {
    return "Coupon has expired.";
  }

  if (coupon.isUsed()) {
    return "Coupon has already been used.";
  }

  coupon.markAsUsed();
  applyDiscount(coupon.discount);

  return "Coupon redeemed successfully.";
}

function isCouponValid(couponCode) {
  const coupon = coupons.find(c => c.code === couponCode);
  return coupon && !coupon.isExpired() && !coupon.isUsed();
}

